"""
MKT Luke chapters 1-6 — three-tier translation written directly to draft JSON files.
Run: python3 scripts/mkt-luke-1-6.py
"""
import json, pathlib

ROOT  = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

# πνεῦμα = Holy Spirit (capitalised in all tiers when divine agent is meant)
# λόγος in Luke = the message/word (not the Johannine Logos)
# σωτήρ / σωτηρία = Savior / salvation (kept in all tiers)
# αἰώνιος = age-to-come life / eternal (noted in context)
# The Magnificat (1:46-55) and Benedictus (1:67-79) receive poetic cadence in T tier

LUKE = {
 "1": {
  "1": {"L":"Inasmuch as many have undertaken to draw up an account of the events that have been fulfilled among us,","M":"Many have attempted to write an orderly account of the events that have been fulfilled among us,","T":"Many writers have set their hand to composing a narrative of the events that have unfolded among us,"},
  "2": {"L":"just as those who from the beginning were eyewitnesses and ministers of the word handed them on to us,","M":"just as they were handed down to us by those who from the beginning were eyewitnesses and servants of the message,","T":"following the testimony of those who were eyewitnesses from the start and who became servants of this message,"},
  "3": {"L":"it seemed good to me also, having followed all things closely from the first, to write them out for you in order, most excellent Theophilus,","M":"it seemed good to me also, having carefully investigated everything from the beginning, to write an orderly account for you, most excellent Theophilus,","T":"it has seemed right for me as well—having carefully traced everything from its origins—to set it out in sequence for you, honored Theophilus,"},
  "4": {"L":"so that you may know the certainty concerning the things in which you have been instructed.","M":"so that you may be certain of the reliability of the things you have been taught.","T":"so that you may have full confidence in what you have been taught."},
  "5": {"L":"In the days of Herod, king of Judea, there was a priest named Zechariah, of the division of Abijah; and he had a wife from the daughters of Aaron, and her name was Elizabeth.","M":"In the time of Herod king of Judea there was a priest named Zechariah, who belonged to the priestly division of Abijah; his wife Elizabeth was also a descendant of Aaron.","T":"During the reign of Herod over Judea there was a priest named Zechariah who served in the division of Abijah. His wife Elizabeth was of priestly lineage—a descendant of Aaron."},
  "6": {"L":"And they were both righteous before God, walking blamelessly in all the commandments and ordinances of the Lord.","M":"Both of them were righteous in the sight of God, observing all the Lord's commands and decrees blamelessly.","T":"Both were righteous before God, living blamelessly in every commandment and requirement the Lord had given."},
  "7": {"L":"But they had no child, because Elizabeth was barren, and both were advanced in their years.","M":"But they were childless because Elizabeth was unable to conceive, and they were both very old.","T":"They had no children, for Elizabeth was barren, and both were well past the age of having a family."},
  "8": {"L":"Now it came to pass, while he was serving as priest before God in the order of his division,","M":"Once when Zechariah's division was on duty and he was serving as priest before God,","T":"One day while his priestly division was serving its rotation before God,"},
  "9": {"L":"according to the custom of the priestly office, it fell to him by lot to enter the temple of the Lord and burn incense.","M":"he was chosen by lot, according to priestly custom, to go into the temple of the Lord and burn incense.","T":"he was chosen by lot—as the priestly custom required—to enter the Lord's sanctuary and offer incense."},
  "10": {"L":"And the whole multitude of the people were praying outside at the hour of the incense offering.","M":"And when the time for the burning of incense came, all the assembled worshippers were praying outside.","T":"The whole assembly of worshippers was gathered outside, praying, at the time of the incense offering."},
  "11": {"L":"And an angel of the Lord appeared to him, standing on the right side of the altar of incense.","M":"Then an angel of the Lord appeared to him, standing at the right side of the altar of incense.","T":"Suddenly an angel of the Lord appeared to him, standing at the right side of the incense altar."},
  "12": {"L":"And Zechariah was troubled when he saw him, and fear fell upon him.","M":"When Zechariah saw him, he was startled and was gripped with fear.","T":"The sight of the angel terrified Zechariah and he was seized with fear."},
  "13": {"L":"But the angel said to him: Do not fear, Zechariah, for your prayer has been heard, and your wife Elizabeth will bear you a son, and you shall call his name John.","M":"But the angel said to him: Do not be afraid, Zechariah; your prayer has been heard. Your wife Elizabeth will bear you a son, and you are to call him John.","T":"The angel said: Don't be afraid, Zechariah—God has heard your prayer. Your wife Elizabeth will conceive and bear a son, and you will name him John."},
  "14": {"L":"And you will have joy and gladness, and many will rejoice at his birth.","M":"He will be a joy and delight to you, and many will rejoice because of his birth,","T":"He will bring you great joy and happiness, and his birth will be a cause for rejoicing among many."},
  "15": {"L":"For he will be great before the Lord, and he shall drink no wine or strong drink, and he will be filled with the Holy Spirit, even from his mother's womb.","M":"for he will be great in the sight of the Lord. He is never to take wine or other fermented drink, and he will be filled with the Holy Spirit even before he is born.","T":"He will be great in the Lord's sight. He is to abstain from wine and strong drink entirely, and he will be filled with the Holy Spirit from before his birth."},
  "16": {"L":"And he will turn many of the sons of Israel to the Lord their God.","M":"He will bring back many of the people of Israel to the Lord their God.","T":"He will turn many in Israel back to the Lord their God."},
  "17": {"L":"And he will go before him in the spirit and power of Elijah, to turn the hearts of fathers to children, and the disobedient to the wisdom of the righteous, to make ready for the Lord a people prepared.","M":"And he will go on before the Lord, in the spirit and power of Elijah, to turn the hearts of the parents to their children and the disobedient to the wisdom of the righteous—to make ready a people prepared for the Lord.","T":"He will go ahead of the Lord in the spirit and power of Elijah, turning the hearts of parents toward their children and the rebellious toward the wisdom of the righteous—preparing a people ready to receive the Lord."},
  "18": {"L":"And Zechariah said to the angel: How will I know this? For I am an old man, and my wife is advanced in years.","M":"Zechariah asked the angel: How can I be sure of this? I am an old man and my wife is well along in years.","T":"Zechariah said to the angel: How can I know this is real? I'm an old man, and my wife is well past childbearing age."},
  "19": {"L":"And the angel answering said to him: I am Gabriel, who stands in the presence of God, and I was sent to speak to you and to bring you this good news.","M":"The angel said to him: I am Gabriel. I stand in the presence of God, and I have been sent to speak to you and to tell you this good news.","T":"The angel replied: I am Gabriel—I stand in the very presence of God. He sent me to you to bring you this good news."},
  "20": {"L":"And behold, you will be silent and unable to speak until the day that these things come to pass, because you did not believe my words, which will be fulfilled in their time.","M":"And now you will be silent and not able to speak until the day this happens, because you did not believe my words, which will come true at their appointed time.","T":"But because you did not believe my words—which will be fulfilled at the right time—you will be struck silent and unable to speak until the day this comes to pass."},
  "21": {"L":"And the people were waiting for Zechariah, and they were wondering at his delay in the temple.","M":"Meanwhile, the people were waiting for Zechariah and wondering why he stayed so long in the temple.","T":"Outside, the people were waiting for Zechariah, puzzled by how long he was taking in the sanctuary."},
  "22": {"L":"And when he came out, he was unable to speak to them; and they realized that he had seen a vision in the temple. And he was making signs to them, and remained mute.","M":"When he came out, he could not speak to them. They realized he had seen a vision in the temple, for he kept making signs to them but remained unable to speak.","T":"When he finally came out, he could not speak a word. They understood he had seen a vision in the sanctuary—he kept gesturing to them but stayed completely mute."},
  "23": {"L":"And it came to pass that when the days of his service were completed, he went to his home.","M":"When his time of service was completed, he returned home.","T":"When his period of temple service ended, he went home."},
  "24": {"L":"After these days Elizabeth his wife conceived, and she kept herself hidden for five months, saying,","M":"After this his wife Elizabeth became pregnant and for five months remained in seclusion.","T":"Some time later his wife Elizabeth became pregnant and kept to herself for five months."},
  "25": {"L":"The Lord has done this for me. In these days he has looked on me to take away my disgrace among the people.","M":"The Lord has done this for me, she said. In these days he has shown his favour and taken away my disgrace among the people.","T":"This is what the Lord has done for me, she said. He has looked on me with favour and removed the shame I bore among my people."},
  "26": {"L":"Now in the sixth month, the angel Gabriel was sent by God to a city of Galilee named Nazareth,","M":"In the sixth month of Elizabeth's pregnancy, God sent the angel Gabriel to Nazareth, a town in Galilee,","T":"Six months into Elizabeth's pregnancy, God sent the angel Gabriel to a town in Galilee called Nazareth,"},
  "27": {"L":"to a virgin betrothed to a man named Joseph, of the house of David; and the virgin's name was Mary.","M":"to a virgin pledged to be married to a man named Joseph, a descendant of David. The virgin's name was Mary.","T":"with a message for a young woman named Mary, who was pledged to marry Joseph, a descendant of David."},
  "28": {"L":"And coming to her, he said: Greetings, favored one! The Lord is with you.","M":"The angel went to her and said: Greetings, you who are highly favoured! The Lord is with you.","T":"Gabriel came to her and said: Greetings, Mary—you are deeply favored by God! The Lord is with you."},
  "29": {"L":"But she was greatly troubled by his word, and was reasoning in her mind what sort of greeting this might be.","M":"Mary was greatly troubled at his words and wondered what kind of greeting this might be.","T":"Mary was deeply unsettled by these words and tried to make sense of what kind of greeting this could be."},
  "30": {"L":"And the angel said to her: Do not fear, Mary, for you have found favor with God.","M":"But the angel said to her: Do not be afraid, Mary; you have found favour with God.","T":"The angel said: Don't be afraid, Mary—you have found extraordinary favor with God."},
  "31": {"L":"And behold, you will conceive in your womb and bear a son, and you shall call his name Jesus.","M":"You will conceive and give birth to a son, and you are to call him Jesus.","T":"You will become pregnant and give birth to a son, and you are to name him Jesus."},
  "32": {"L":"He will be great, and will be called the Son of the Most High, and the Lord God will give to him the throne of his father David;","M":"He will be great and will be called the Son of the Most High. The Lord God will give him the throne of his father David,","T":"He will be great—called the Son of the Most High. The Lord God will give him the throne of his ancestor David;"},
  "33": {"L":"and he will reign over the house of Jacob forever, and of his kingdom there will be no end.","M":"and he will reign over Jacob's descendants forever; his kingdom will never end.","T":"he will reign over the people of Jacob forever, and his kingdom will have no end."},
  "34": {"L":"And Mary said to the angel: How will this be, since I have no relations with a man?","M":"How will this be, Mary asked the angel, since I am a virgin?","T":"Mary said to the angel: But how can this happen? I have never been with a man."},
  "35": {"L":"And the angel answering said to her: The Holy Spirit will come upon you, and the power of the Most High will overshadow you; therefore also the holy one to be born will be called the Son of God.","M":"The angel answered: The Holy Spirit will come on you, and the power of the Most High will overshadow you. So the holy one to be born will be called the Son of God.","T":"The angel replied: The Holy Spirit will come upon you, and the power of the Most High will cover you. Because of this, the holy child born to you will be called the Son of God."},
  "36": {"L":"And behold, your relative Elizabeth—even she has conceived a son in her old age, and this is her sixth month for her who was called barren.","M":"Even Elizabeth your relative is going to have a child in her old age, and she who was said to be unable to conceive is in her sixth month.","T":"And consider this: your relative Elizabeth has also conceived a son in her old age—she who was called barren is already six months along."},
  "37": {"L":"For nothing will be impossible with God.","M":"For no word from God will ever fail.","T":"For nothing is impossible with God."},
  "38": {"L":"And Mary said: Behold, I am the servant of the Lord; let it be to me according to your word. And the angel departed from her.","M":"I am the Lord's servant, Mary answered. May your word to me be fulfilled. Then the angel left her.","T":"Mary said: I am the Lord's servant. Let it be exactly as you have said. And with that the angel left her."},
  "39": {"L":"And in those days Mary arose and went with haste to a city in the hill country of Judah,","M":"At that time Mary got ready and hurried to a town in the hill country of Judea,","T":"In those days Mary set out quickly and traveled to a town in the hill country of Judea,"},
  "40": {"L":"and she entered the house of Zechariah and greeted Elizabeth.","M":"where she entered Zechariah's home and greeted Elizabeth.","T":"where she entered Zechariah's home and greeted Elizabeth."},
  "41": {"L":"And it came to pass that when Elizabeth heard the greeting of Mary, the baby leaped in her womb. And Elizabeth was filled with the Holy Spirit,","M":"When Elizabeth heard Mary's greeting, the baby leaped in her womb, and Elizabeth was filled with the Holy Spirit.","T":"The moment Elizabeth heard Mary's greeting, the baby inside her leaped for joy, and Elizabeth was filled with the Holy Spirit."},
  "42": {"L":"and she cried out with a loud cry and said: Blessed are you among women, and blessed is the fruit of your womb!","M":"In a loud voice she exclaimed: Blessed are you among women, and blessed is the child you will bear!","T":"She cried out in a loud voice: You are the most blessed of all women, and blessed is the child you carry!"},
  "43": {"L":"And from where is this to me, that the mother of my Lord should come to me?","M":"But why am I so favoured, that the mother of my Lord should come to me?","T":"How has this honor come to me—that the mother of my Lord should visit me?"},
  "44": {"L":"For behold, when the sound of your greeting came to my ears, the baby in my womb leaped for joy.","M":"As soon as the sound of your greeting reached my ears, the baby in my womb leaped for joy.","T":"The moment your greeting reached my ears, the child inside me leaped with joy."},
  "45": {"L":"And blessed is she who believed that there would be fulfillment of what was spoken to her from the Lord.","M":"Blessed is she who has believed that the Lord would fulfil his promises to her!","T":"How blessed you are for believing that what the Lord promised you would actually come to pass!"},
  "46": {"L":"And Mary said: My soul magnifies the Lord,","M":"And Mary said: My soul glorifies the Lord","T":"And Mary broke into song: My whole being magnifies the Lord,"},
  "47": {"L":"and my spirit rejoices in God my Savior,","M":"and my spirit rejoices in God my Saviour,","T":"my spirit overflows with joy in God my Savior,"},
  "48": {"L":"for he has looked upon the humble state of his servant. For behold, from now on all generations will call me blessed;","M":"for he has been mindful of the humble state of his servant. From now on all generations will call me blessed,","T":"for he has turned his eye toward the lowliness of his servant—from now on every generation will call me blessed,"},
  "49": {"L":"for he who is mighty has done great things for me, and holy is his name.","M":"for the Mighty One has done great things for me—holy is his name.","T":"for the Mighty One has accomplished great things for me—holy is his name."},
  "50": {"L":"And his mercy is from generation to generation on those who fear him.","M":"His mercy extends to those who fear him, from generation to generation.","T":"His mercy flows to all who hold him in reverence, from one generation to the next."},
  "51": {"L":"He has shown strength with his arm; he has scattered the proud in the thought of their hearts.","M":"He has performed mighty deeds with his arm; he has scattered those who are proud in their inmost thoughts.","T":"He has unleashed the power of his arm—scattering those whose hearts are swollen with pride."},
  "52": {"L":"He has brought down the powerful from their thrones, and has lifted up the lowly.","M":"He has brought down rulers from their thrones but has lifted up the humble.","T":"He has toppled rulers from their thrones and raised up the humble in their place."},
  "53": {"L":"He has filled the hungry with good things, and the rich he has sent away empty.","M":"He has filled the hungry with good things but has sent the rich away empty.","T":"He has satisfied the hungry with good things and sent the wealthy away with nothing."},
  "54": {"L":"He has helped his servant Israel, in remembrance of his mercy,","M":"He has helped his servant Israel, remembering to be merciful","T":"He has taken hold of his servant Israel, faithful to his covenant mercy,"},
  "55": {"L":"as he spoke to our fathers, to Abraham and to his offspring forever.","M":"to Abraham and his descendants forever, just as he promised our ancestors.","T":"just as he promised our ancestors—to Abraham and his descendants forever."},
  "56": {"L":"And Mary remained with her about three months, and then returned to her home.","M":"Mary stayed with Elizabeth for about three months and then returned home.","T":"Mary stayed with Elizabeth about three months before returning to her own home."},
  "57": {"L":"Now the time came for Elizabeth to give birth, and she bore a son.","M":"When it was time for Elizabeth to have her baby, she gave birth to a son.","T":"When the time came, Elizabeth gave birth to a son."},
  "58": {"L":"And her neighbors and relatives heard that the Lord had shown great mercy to her, and they rejoiced with her.","M":"Her neighbours and relatives heard that the Lord had shown her great mercy, and they shared her joy.","T":"Her neighbors and relatives heard how the Lord had shown his great mercy to her, and they celebrated with her."},
  "59": {"L":"And on the eighth day they came to circumcise the child. And they were calling him by the name of his father, Zechariah.","M":"On the eighth day they came to circumcise the child, and they were going to name him after his father Zechariah,","T":"On the eighth day they gathered to circumcise the child. They assumed he would be named Zechariah after his father—"},
  "60": {"L":"And his mother answered and said: No; he shall be called John.","M":"but his mother spoke up and said: No! He is to be called John.","T":"but his mother spoke up firmly: No—he is to be called John."},
  "61": {"L":"And they said to her: There is no one among your relatives who is called by this name.","M":"They said to her: There is no one among your relatives who has that name.","T":"But they objected: No one in your family has ever had that name."},
  "62": {"L":"And they made signs to his father, asking what he wanted him to be called.","M":"Then they made signs to his father, to find out what he would like to name the child.","T":"They turned to Zechariah, gesturing to find out what name he wanted."},
  "63": {"L":"And asking for a writing tablet, he wrote, saying: His name is John. And they all marveled.","M":"He asked for a writing tablet and wrote: His name is John. Everyone was amazed.","T":"He asked for a writing tablet and wrote plainly: His name is John. Everyone was astonished."},
  "64": {"L":"And immediately his mouth was opened and his tongue loosed, and he spoke, blessing God.","M":"Immediately his mouth was opened and his tongue set free, and he began to speak, praising God.","T":"At that instant his mouth opened, his tongue was freed, and he began to speak—praising God."},
  "65": {"L":"And fear came on all their neighbors. And all these things were talked about throughout all the hill country of Judea.","M":"All the neighbours were filled with awe, and throughout the hill country of Judea people were talking about all these things.","T":"A sense of awe fell on all their neighbors, and news of these events spread through the entire hill country of Judea."},
  "66": {"L":"And all who heard them laid them up in their heart, saying: What then will this child be? For the hand of the Lord was with him.","M":"Everyone who heard this wondered about it, asking: What then is this child going to be? For the Lord's hand was with him.","T":"Everyone who heard about it took it to heart and wondered: What is this child going to become? For the Lord's hand was clearly upon him."},
  "67": {"L":"And Zechariah his father was filled with the Holy Spirit and prophesied, saying:","M":"His father Zechariah was filled with the Holy Spirit and prophesied:","T":"His father Zechariah was filled with the Holy Spirit and broke into prophetic song:"},
  "68": {"L":"Blessed be the Lord God of Israel, for he has visited and redeemed his people,","M":"Praise be to the Lord, the God of Israel, because he has come to his people and redeemed them.","T":"Praise the Lord God of Israel—he has come to his people and set them free!"},
  "69": {"L":"and has raised up a horn of salvation for us in the house of David his servant—","M":"He has raised up a horn of salvation for us in the house of his servant David","T":"He has raised up a mighty Savior for us from the royal line of his servant David—"},
  "70": {"L":"as he spoke by the mouth of his holy prophets from of old—","M":"(as he said through his holy prophets of long ago),","T":"just as he promised long ago through his holy prophets—"},
  "71": {"L":"salvation from our enemies and from the hand of all who hate us;","M":"salvation from our enemies and from the hand of all who hate us—","T":"rescue from our enemies and deliverance from all who hate us,"},
  "72": {"L":"to show mercy to our fathers and to remember his holy covenant,","M":"to show mercy to our ancestors and to remember his holy covenant,","T":"to show the mercy he promised our ancestors, honoring his holy covenant,"},
  "73": {"L":"the oath that he swore to our father Abraham, to grant us","M":"the oath he swore to our father Abraham:","T":"the oath he swore to our ancestor Abraham—"},
  "74": {"L":"that, being delivered from the hand of our enemies, we might serve him without fear,","M":"to rescue us from the hand of our enemies, and to enable us to serve him without fear","T":"to free us from our enemies so we could serve him without fear,"},
  "75": {"L":"in holiness and righteousness before him all our days.","M":"in holiness and righteousness before him all our days.","T":"living in holiness and right relationship with him all our days."},
  "76": {"L":"And you, child, will be called prophet of the Most High; for you will go before the Lord to prepare his ways,","M":"And you, my child, will be called a prophet of the Most High; for you will go on before the Lord to prepare the way for him,","T":"And you, my child—you will be called a prophet of the Most High, for you will go ahead of the Lord to prepare his path,"},
  "77": {"L":"to give knowledge of salvation to his people in the forgiveness of their sins,","M":"to give his people the knowledge of salvation through the forgiveness of their sins,","T":"bringing his people the knowledge of salvation through the forgiveness of their sins—"},
  "78": {"L":"because of the tender mercy of our God, whereby the sunrise from on high shall visit us,","M":"because of the tender mercy of our God, by which the rising sun will come to us from heaven","T":"all flowing from the tender mercy of our God, by which the dawn from on high will break upon us,"},
  "79": {"L":"to give light to those who sit in darkness and in the shadow of death, to guide our feet into the way of peace.","M":"to shine on those living in darkness and in the shadow of death, to guide our feet into the path of peace.","T":"to shine on all who sit in darkness and death's shadow, and to guide our feet onto the path of peace."},
  "80": {"L":"And the child grew and became strong in spirit, and he was in the deserts until the day of his manifestation to Israel.","M":"And the child grew and became strong in spirit; and he lived in the wilderness until he appeared publicly to Israel.","T":"The child grew strong in spirit and lived in the wilderness until the day he appeared publicly to Israel."}
 },
 "2": {
  "1": {"L":"Now it came to pass in those days that a decree went out from Caesar Augustus that all the world should be registered.","M":"In those days Caesar Augustus issued a decree that a census should be taken of the entire Roman world.","T":"In those days Emperor Augustus issued an order for a census of the whole Roman world."},
  "2": {"L":"This was the first registration when Quirinius was governor of Syria.","M":"This was the first census that took place while Quirinius was governor of Syria.","T":"This was the first census carried out while Quirinius governed Syria."},
  "3": {"L":"And all were going to be registered, each to his own city.","M":"And everyone went to their own town to register.","T":"Everyone traveled to their ancestral hometown to register."},
  "4": {"L":"And Joseph also went up from Galilee, from the city of Nazareth, to Judea, to the city of David, which is called Bethlehem, because he was of the house and family of David,","M":"So Joseph also went up from the town of Nazareth in Galilee to Judea, to Bethlehem the town of David, because he belonged to the house and line of David.","T":"Joseph therefore went up from Galilee—from Nazareth—to Judea, to the city of David called Bethlehem, because he belonged to the house and lineage of David."},
  "5": {"L":"to be registered with Mary, who was betrothed to him and was with child.","M":"He went there to register with Mary, who was pledged to be married to him and was expecting a child.","T":"He went to register along with Mary, to whom he was engaged—and she was expecting a child."},
  "6": {"L":"And it came to pass that while they were there, the days were fulfilled for her to give birth.","M":"While they were there, the time came for the baby to be born,","T":"While they were in Bethlehem the time came for the baby to be born,"},
  "7": {"L":"And she gave birth to her firstborn son, and wrapped him in swaddling cloths, and laid him in a manger, because there was no room for them in the inn.","M":"and she gave birth to her firstborn, a son. She wrapped him in cloths and placed him in a manger, because there was no guest room available for them.","T":"and she gave birth to her firstborn son. She wrapped him in strips of cloth and laid him in a feeding trough, because no lodging was available for them."},
  "8": {"L":"And in the same region there were shepherds out in the field, keeping watch over their flock by night.","M":"And there were shepherds living out in the fields nearby, keeping watch over their flocks at night.","T":"In the fields nearby, shepherds were keeping night watch over their flocks."},
  "9": {"L":"And an angel of the Lord appeared to them, and the glory of the Lord shone around them, and they were filled with great fear.","M":"An angel of the Lord appeared to them, and the glory of the Lord shone around them, and they were terrified.","T":"Suddenly an angel of the Lord appeared to them, and the radiance of the Lord blazed around them—they were overcome with terror."},
  "10": {"L":"And the angel said to them: Do not fear, for behold, I bring you good news of great joy that will be for all the people.","M":"But the angel said to them: Do not be afraid. I bring you good news that will cause great joy for all the people.","T":"But the angel said: Don't be afraid! I bring you wonderful news—great joy for all people."},
  "11": {"L":"For there is born to you today in the city of David a Savior, who is Christ the Lord.","M":"Today in the town of David a Saviour has been born to you; he is the Messiah, the Lord.","T":"Today in the city of David, a Savior has been born to you—he is the Messiah, the Lord."},
  "12": {"L":"And this will be a sign for you: you will find a baby wrapped in swaddling cloths and lying in a manger.","M":"This will be a sign to you: You will find a baby wrapped in cloths and lying in a manger.","T":"Here is the sign to confirm it: you will find a newborn baby, wrapped in cloth and lying in a feeding trough."},
  "13": {"L":"And suddenly there was with the angel a multitude of the heavenly host praising God and saying,","M":"Suddenly a great company of the heavenly host appeared with the angel, praising God and saying,","T":"At that moment a vast company of the heavenly army appeared with the angel, praising God:"},
  "14": {"L":"Glory to God in the highest, and on earth peace among those with whom he is pleased.","M":"Glory to God in the highest heaven, and on earth peace to those on whom his favour rests.","T":"Glory to God in the highest! And peace on earth to all those who carry his favor."},
  "15": {"L":"And it came to pass, when the angels departed from them into heaven, the shepherds said one to another: Let us go over to Bethlehem and see this thing that has come to pass, which the Lord has made known to us.","M":"When the angels had left them and gone into heaven, the shepherds said to one another: Let's go to Bethlehem and see this thing that has happened, which the Lord has told us about.","T":"When the angels had returned to heaven, the shepherds said to each other: Let's go straight to Bethlehem and see this event that the Lord has made known to us."},
  "16": {"L":"And they went with haste and found Mary and Joseph, and the baby lying in the manger.","M":"So they hurried off and found Mary and Joseph, and the baby, who was lying in the manger.","T":"They hurried off and found Mary and Joseph, and the baby lying in the feeding trough."},
  "17": {"L":"And when they saw it, they made known the word that was spoken to them about this child.","M":"When they had seen him, they spread the word concerning what had been told them about this child,","T":"Once they had seen the child, they spread the news of what they had been told about him,"},
  "18": {"L":"And all who heard it marveled at the things that were spoken to them by the shepherds.","M":"and all who heard it were amazed at what the shepherds said to them.","T":"and everyone who heard it was amazed at what the shepherds told them."},
  "19": {"L":"But Mary treasured all these things, pondering them in her heart.","M":"But Mary treasured up all these things and pondered them in her heart.","T":"But Mary quietly held all of these things close, turning them over in her heart."},
  "20": {"L":"And the shepherds returned, glorifying and praising God for all they had heard and seen, as it had been told to them.","M":"The shepherds returned, glorifying and praising God for all the things they had heard and seen, which were just as they had been told.","T":"The shepherds returned, glorifying and praising God for everything they had heard and seen—it was exactly as they had been told."},
  "21": {"L":"And when eight days were fulfilled for his circumcision, his name was called Jesus, the name given by the angel before he was conceived in the womb.","M":"On the eighth day, when it was time to circumcise the child, he was named Jesus, the name the angel had given him before he was conceived.","T":"On the eighth day, when the time came for his circumcision, he was named Jesus—the name the angel had given before he was even conceived."},
  "22": {"L":"And when the days of their purification were fulfilled according to the law of Moses, they brought him up to Jerusalem to present him to the Lord,","M":"When the time came for the purification rites required by the Law of Moses, Joseph and Mary took him to Jerusalem to present him to the Lord,","T":"When the days required for purification under Moses' law were completed, they brought him up to Jerusalem to present him to the Lord,"},
  "23": {"L":"as it is written in the law of the Lord: Every male who opens the womb shall be called holy to the Lord,","M":"as it is written in the Law of the Lord: Every firstborn male is to be consecrated to the Lord,","T":"as the Law of the Lord requires: Every firstborn male shall be dedicated to the Lord,"},
  "24": {"L":"and to offer a sacrifice according to what is said in the law of the Lord: A pair of turtledoves, or two young pigeons.","M":"and to offer a sacrifice in keeping with what is said in the Law of the Lord: a pair of doves or two young pigeons.","T":"and to offer the sacrifice prescribed in the Lord's law: a pair of doves or two young pigeons."},
  "25": {"L":"And behold, there was a man in Jerusalem whose name was Simeon, and this man was righteous and devout, waiting for the consolation of Israel, and the Holy Spirit was upon him.","M":"Now there was a man in Jerusalem called Simeon, who was righteous and devout. He was waiting for the consolation of Israel, and the Holy Spirit was on him.","T":"At that time there was a man in Jerusalem named Simeon—righteous and devout, waiting for the consolation of Israel—and the Holy Spirit rested on him."},
  "26": {"L":"And it had been revealed to him by the Holy Spirit that he would not see death before he had seen the Lord's Christ.","M":"It had been revealed to him by the Holy Spirit that he would not die before he had seen the Lord's Messiah.","T":"The Holy Spirit had revealed to him that he would not die before he had seen the Lord's Messiah."},
  "27": {"L":"And he came in the Spirit into the temple; and when the parents brought in the child Jesus, to do for him after the custom of the law,","M":"Moved by the Spirit, he went into the temple courts. When the parents brought in the child Jesus to do for him what the custom of the Law required,","T":"Led by the Spirit, he entered the temple courts. When the parents brought in the child Jesus to carry out what the law required,"},
  "28": {"L":"he took him up in his arms, and blessed God, and said:","M":"Simeon took him in his arms and praised God, saying:","T":"Simeon took the child in his arms and praised God:"},
  "29": {"L":"Now you release your servant, O Lord, according to your word, in peace;","M":"Sovereign Lord, as you have promised, you may now dismiss your servant in peace;","T":"Lord, now you can let your servant depart in peace, just as you promised,"},
  "30": {"L":"for my eyes have seen your salvation,","M":"for my eyes have seen your salvation,","T":"for my eyes have seen your salvation—"},
  "31": {"L":"which you have prepared in the presence of all peoples,","M":"which you have prepared in the sight of all nations:","T":"the deliverance you have made ready in full view of every nation:"},
  "32": {"L":"a light for revelation to the Gentiles, and glory for your people Israel.","M":"a light for revelation to the Gentiles, and the glory of your people Israel.","T":"a light to illuminate the nations, and the glory of your people Israel."},
  "33": {"L":"And his father and mother were marveling at the things which were spoken concerning him.","M":"The child's father and mother marvelled at what was said about him.","T":"The child's father and mother were astonished at what was being said about him."},
  "34": {"L":"And Simeon blessed them, and said to Mary his mother: Behold, this child is set for the falling and the rising of many in Israel, and for a sign that is spoken against,","M":"Then Simeon blessed them and said to Mary, his mother: This child is destined to cause the falling and rising of many in Israel, and to be a sign that will be spoken against,","T":"Then Simeon blessed them and said to Mary his mother: This child is destined to bring about the fall and rise of many in Israel, and to be a sign that people will oppose—"},
  "35": {"L":"and a sword will pierce through your own soul also, so that thoughts from many hearts may be revealed.","M":"so that the thoughts of many hearts will be revealed. And a sword will pierce your own soul too.","T":"and a sword will pierce through your own soul as well—so that what lies hidden in many hearts may be laid bare."},
  "36": {"L":"And there was a prophetess, Anna the daughter of Phanuel, of the tribe of Asher. She was advanced in years, having lived with her husband seven years from her virginity,","M":"There was also a prophet, Anna, the daughter of Penuel, of the tribe of Asher. She was very old; she had lived with her husband seven years after her marriage,","T":"There was also a prophetess named Anna, daughter of Phanuel, from the tribe of Asher. She was very old—having lived with her husband seven years after her marriage,"},
  "37": {"L":"and she was a widow until she was eighty-four. She did not depart from the temple, worshiping with fasting and prayer night and day.","M":"and then was a widow until she was eighty-four. She never left the temple but worshipped night and day, fasting and praying.","T":"then a widow until she was eighty-four. She never left the temple but served God night and day with fasting and prayer."},
  "38": {"L":"And coming up at that very hour, she gave thanks to God and spoke of him to all who were waiting for the redemption of Jerusalem.","M":"Coming up to them at that very moment, she gave thanks to God and spoke about the child to all who were looking forward to the redemption of Jerusalem.","T":"Coming forward at that very moment, she gave thanks to God and spoke about the child to everyone who was waiting for Jerusalem's redemption."},
  "39": {"L":"And when they had completed everything according to the law of the Lord, they returned to Galilee, to their own city of Nazareth.","M":"When Joseph and Mary had done everything required by the Law of the Lord, they returned to Galilee to their own town of Nazareth.","T":"When they had done everything required by the Lord's law, they returned to Galilee and their hometown of Nazareth."},
  "40": {"L":"And the child grew and became strong, filled with wisdom; and the grace of God was upon him.","M":"And the child grew and became strong; he was filled with wisdom, and the grace of God was on him.","T":"The child grew and became strong, filled with wisdom, and the grace of God rested on him."},
  "41": {"L":"And his parents went to Jerusalem every year at the feast of the Passover.","M":"Every year Jesus' parents went to Jerusalem for the Festival of the Passover.","T":"Every year his parents traveled to Jerusalem for the Passover festival."},
  "42": {"L":"And when he was twelve years old, they went up according to the custom of the feast.","M":"When he was twelve years old, they went up to the festival, according to the custom.","T":"When he was twelve, they made the journey as usual."},
  "43": {"L":"And when the days were completed, as they were returning, the boy Jesus remained behind in Jerusalem. And his parents did not know it,","M":"After the festival was over, while his parents were returning home, the boy Jesus stayed behind in Jerusalem, but they were unaware of it.","T":"When the festival was over and his parents headed home, the boy Jesus stayed behind in Jerusalem without them knowing."},
  "44": {"L":"but supposing him to be in the traveling company, they went a day's journey; and they sought for him among their relatives and acquaintances,","M":"Thinking he was in their company, they traveled on for a day. Then they began looking for him among their relatives and friends.","T":"Assuming he was traveling with others in their group, they went a full day's journey before searching for him among relatives and friends."},
  "45": {"L":"and when they did not find him, they returned to Jerusalem, seeking him.","M":"When they did not find him, they went back to Jerusalem to look for him.","T":"When they could not find him, they turned back to Jerusalem to search."},
  "46": {"L":"And it came to pass that after three days they found him in the temple, sitting among the teachers, listening to them and asking them questions.","M":"After three days they found him in the temple courts, sitting among the teachers, listening to them and asking them questions.","T":"Three days later they found him in the temple, sitting in the middle of the teachers, listening to them and asking questions."},
  "47": {"L":"And all who heard him were amazed at his understanding and his answers.","M":"Everyone who heard him was amazed at his understanding and his answers.","T":"Everyone who heard him was astonished at his understanding and the answers he gave."},
  "48": {"L":"And when they saw him, they were astonished. And his mother said to him: Child, why have you treated us this way? Behold, your father and I have been searching for you in great distress.","M":"When his parents saw him, they were astonished. His mother said to him: Son, why have you treated us like this? Your father and I have been anxiously searching for you.","T":"When his parents saw him, they were overcome. His mother said: Son, why did you do this to us? Your father and I have been searching for you in anguish."},
  "49": {"L":"And he said to them: Why were you seeking me? Did you not know that I must be in my Father's house?","M":"Why were you searching for me? he asked. Didn't you know I had to be in my Father's house?","T":"He replied: Why were you looking for me? Didn't you know I had to be in my Father's house?"},
  "50": {"L":"And they did not understand the saying that he spoke to them.","M":"But they did not understand what he was saying to them.","T":"But they did not grasp what he meant."},
  "51": {"L":"And he went down with them and came to Nazareth, and he was submissive to them. And his mother treasured all these things in her heart.","M":"Then he went down to Nazareth with them and was obedient to them. But his mother treasured all these things in her heart.","T":"He went back to Nazareth with them and was obedient to them. His mother kept all these things stored in her heart."},
  "52": {"L":"And Jesus increased in wisdom and in stature, and in favor with God and man.","M":"And Jesus grew in wisdom and stature, and in favour with God and man.","T":"And Jesus grew in wisdom and maturity, gaining favor with both God and people."}
 },
 "3": {
  "1": {"L":"Now in the fifteenth year of the reign of Tiberius Caesar, when Pontius Pilate was governor of Judea, and Herod was tetrarch of Galilee, and his brother Philip was tetrarch of the region of Ituraea and Trachonitis, and Lysanias was tetrarch of Abilene,","M":"In the fifteenth year of the reign of Tiberius Caesar—when Pontius Pilate was governor of Judea, Herod tetrarch of Galilee, his brother Philip tetrarch of Iturea and Traconitis, and Lysanias tetrarch of Abilene—","T":"In the fifteenth year of Emperor Tiberius's reign—when Pontius Pilate governed Judea, Herod ruled Galilee, his brother Philip ruled Iturea and Trachonitis, and Lysanias ruled Abilene—"},
  "2": {"L":"in the high priesthood of Annas and Caiaphas, the word of God came to John the son of Zechariah in the wilderness.","M":"during the high priesthood of Annas and Caiaphas, the word of God came to John son of Zechariah in the wilderness.","T":"during the high priesthood of Annas and Caiaphas—the word of God came to John, son of Zechariah, in the wilderness."},
  "3": {"L":"And he went into all the region around the Jordan, proclaiming a baptism of repentance for the forgiveness of sins.","M":"He went into all the country around the Jordan, preaching a baptism of repentance for the forgiveness of sins.","T":"He went throughout the whole region around the Jordan, proclaiming a baptism of repentance for the forgiveness of sins."},
  "4": {"L":"As it is written in the book of the words of Isaiah the prophet: A voice of one crying in the wilderness: Prepare the way of the Lord, make his paths straight.","M":"As it is written in the book of the words of Isaiah the prophet: A voice of one calling in the wilderness: Prepare the way for the Lord, make straight paths for him.","T":"This is what Isaiah the prophet wrote: A voice calling in the wilderness—Prepare the road for the Lord; make his paths straight!"},
  "5": {"L":"Every valley shall be filled, and every mountain and hill shall be brought low, and the crooked shall become straight, and the rough ways smooth,","M":"Every valley shall be filled in, every mountain and hill made low. The crooked roads shall become straight, the rough ways smooth.","T":"Every valley will be filled in, every mountain and hill leveled; the winding roads will be straightened and the rough terrain made smooth."},
  "6": {"L":"and all flesh shall see the salvation of God.","M":"And all people will see God's salvation.","T":"And every person on earth will see God's salvation."},
  "7": {"L":"He said therefore to the crowds that came out to be baptized by him: You offspring of vipers! Who warned you to flee from the coming wrath?","M":"John said to the crowds coming out to be baptised by him: You brood of vipers! Who warned you to flee from the coming wrath?","T":"To the crowds coming out to be baptized, John said: You snake-brood! Who tipped you off to escape the coming judgment?"},
  "8": {"L":"Bear fruits therefore worthy of repentance, and do not begin to say to yourselves: We have Abraham as our father; for I tell you, God is able from these stones to raise up children for Abraham.","M":"Produce fruit in keeping with repentance. And do not begin to say to yourselves: We have Abraham as our father. For I tell you that out of these stones God can raise up children for Abraham.","T":"Show by the way you live that you have genuinely turned to God—and don't tell yourselves: We have Abraham as our ancestor. I'm warning you, God could create children for Abraham out of these stones."},
  "9": {"L":"Even now the axe is laid to the root of the trees. Every tree therefore that does not bear good fruit is cut down and thrown into the fire.","M":"The axe is already at the root of the trees, and every tree that does not produce good fruit will be cut down and thrown into the fire.","T":"The axe is already positioned at the base of the trees. Every tree that fails to produce good fruit will be chopped down and thrown into the fire."},
  "10": {"L":"And the crowds asked him: What then shall we do?","M":"What should we do then? the crowd asked.","T":"The people asked him: Then what should we do?"},
  "11": {"L":"And he answered them: The one who has two tunics, let him share with him who has none, and the one who has food, let him do likewise.","M":"John answered: Anyone who has two shirts should share with the one who has none, and anyone who has food should do the same.","T":"John answered: If you have two shirts, give one to someone who has none. If you have food, share it with those who are hungry."},
  "12": {"L":"Tax collectors also came to be baptized and said to him: Teacher, what shall we do?","M":"Even tax collectors came to be baptised. Teacher, what should we do? they asked.","T":"Even tax collectors came to be baptized and asked: Teacher, what should we do?"},
  "13": {"L":"And he said to them: Collect no more than you are authorized to collect.","M":"Don't collect any more than you are required to, he told them.","T":"He told them: Collect only what the law requires—nothing more."},
  "14": {"L":"Soldiers also asked him: And we, what shall we do? And he said to them: Do not extort money from anyone by violence or false accusation, and be content with your wages.","M":"Then some soldiers asked him: And what should we do? He replied: Don't extort money and don't accuse people falsely—be content with your pay.","T":"Some soldiers asked him the same question: And us—what should we do? He replied: No extortion, no false accusations—and be satisfied with your wages."},
  "15": {"L":"Now as the people were in expectation, and all were questioning in their hearts concerning John, whether he might be the Christ,","M":"The people were waiting expectantly and were all wondering in their hearts if John might possibly be the Messiah.","T":"The people were filled with anticipation, and everyone was wondering in their hearts whether John might be the Messiah."},
  "16": {"L":"John answered them all, saying: I baptize you with water; but one mightier than I is coming, the strap of whose sandals I am not worthy to untie. He will baptize you with the Holy Spirit and fire.","M":"John answered them all: I baptise you with water. But one who is more powerful than I will come, the straps of whose sandals I am not worthy to untie. He will baptise you with the Holy Spirit and fire.","T":"John answered everyone: I baptize you with water. But someone far more powerful than I is coming—I'm not even worthy to untie his sandals. He will baptize you with the Holy Spirit and with fire."},
  "17": {"L":"His winnowing fork is in his hand, to clear his threshing floor and to gather the wheat into his barn, but the chaff he will burn with unquenchable fire.","M":"His winnowing fork is in his hand to clear his threshing floor and to gather the wheat into his barn, but he will burn up the chaff with unquenchable fire.","T":"He comes with his threshing fork ready—to separate wheat from chaff, gathering the grain into his storehouse and burning the chaff in an inextinguishable fire."},
  "18": {"L":"So with many other exhortations he preached the good news to the people.","M":"And with many other words John exhorted the people and proclaimed the good news to them.","T":"And with many such warnings and encouragements, he proclaimed the good news to the people."},
  "19": {"L":"But Herod the tetrarch, who had been reproved by him concerning Herodias his brother's wife and all the evil things that Herod had done,","M":"But when John rebuked Herod the tetrarch because of his marriage to Herodias, his brother's wife, and all the other evil things he had done,","T":"But Herod the ruler, whom John had rebuked for marrying Herodias his brother's wife—and for all his other misdeeds—"},
  "20": {"L":"added this to all his other evils—he locked up John in prison.","M":"Herod added this to them all: he locked John up in prison.","T":"topped everything by throwing John in prison."},
  "21": {"L":"Now when all the people were baptized, and when Jesus also had been baptized and was praying, the heavens were opened,","M":"When all the people were being baptised, Jesus was baptised too. And as he was praying, heaven was opened","T":"When all the people had been baptized, Jesus was baptized as well. While he was praying, the sky opened—"},
  "22": {"L":"and the Holy Spirit descended on him in bodily form, like a dove; and a voice came from heaven: You are my beloved Son; with you I am well pleased.","M":"and the Holy Spirit descended on him in bodily form like a dove. And a voice came from heaven: You are my Son, whom I love; with you I am well pleased.","T":"and the Holy Spirit descended on him in a physical form like a dove. A voice came from heaven: You are my Son, the one I cherish—you bring me great joy."},
  "23": {"L":"And Jesus himself was about thirty years old when he began his ministry, being the son (as was supposed) of Joseph, the son of Heli,","M":"Now Jesus himself was about thirty years old when he began his ministry. He was the son, so it was thought, of Joseph, the son of Heli,","T":"Jesus was about thirty years old when he began his ministry. He was known as the son of Joseph, son of Heli,"},
  "24": {"L":"the son of Matthat, the son of Levi, the son of Melchi, the son of Jannai, the son of Joseph,","M":"the son of Matthat, the son of Levi, the son of Melchi, the son of Jannai, the son of Joseph,","T":"son of Matthat, son of Levi, son of Melchi, son of Jannai, son of Joseph,"},
  "25": {"L":"the son of Mattathias, the son of Amos, the son of Nahum, the son of Esli, the son of Naggai,","M":"the son of Mattathias, the son of Amos, the son of Nahum, the son of Esli, the son of Naggai,","T":"son of Mattathias, son of Amos, son of Nahum, son of Esli, son of Naggai,"},
  "26": {"L":"the son of Maath, the son of Mattathias, the son of Semein, the son of Josech, the son of Joda,","M":"the son of Maath, the son of Mattathias, the son of Semein, the son of Josech, the son of Joda,","T":"son of Maath, son of Mattathias, son of Semein, son of Josech, son of Joda,"},
  "27": {"L":"the son of Joanan, the son of Rhesa, the son of Zerubbabel, the son of Shealtiel, the son of Neri,","M":"the son of Joanan, the son of Rhesa, the son of Zerubbabel, the son of Shealtiel, the son of Neri,","T":"son of Joanan, son of Rhesa, son of Zerubbabel, son of Shealtiel, son of Neri,"},
  "28": {"L":"the son of Melchi, the son of Addi, the son of Cosam, the son of Elmadam, the son of Er,","M":"the son of Melchi, the son of Addi, the son of Cosam, the son of Elmadam, the son of Er,","T":"son of Melchi, son of Addi, son of Cosam, son of Elmadam, son of Er,"},
  "29": {"L":"the son of Joshua, the son of Eliezer, the son of Jorim, the son of Matthat, the son of Levi,","M":"the son of Joshua, the son of Eliezer, the son of Jorim, the son of Matthat, the son of Levi,","T":"son of Joshua, son of Eliezer, son of Jorim, son of Matthat, son of Levi,"},
  "30": {"L":"the son of Simeon, the son of Judah, the son of Joseph, the son of Jonam, the son of Eliakim,","M":"the son of Simeon, the son of Judah, the son of Joseph, the son of Jonam, the son of Eliakim,","T":"son of Simeon, son of Judah, son of Joseph, son of Jonam, son of Eliakim,"},
  "31": {"L":"the son of Melea, the son of Menna, the son of Mattatha, the son of Nathan, the son of David,","M":"the son of Melea, the son of Menna, the son of Mattatha, the son of Nathan, the son of David,","T":"son of Melea, son of Menna, son of Mattatha, son of Nathan, son of David,"},
  "32": {"L":"the son of Jesse, the son of Obed, the son of Boaz, the son of Sala, the son of Nahshon,","M":"the son of Jesse, the son of Obed, the son of Boaz, the son of Sala, the son of Nahshon,","T":"son of Jesse, son of Obed, son of Boaz, son of Sala, son of Nahshon,"},
  "33": {"L":"the son of Amminadab, the son of Admin, the son of Arni, the son of Hezron, the son of Perez, the son of Judah,","M":"the son of Amminadab, the son of Ram, the son of Hezron, the son of Perez, the son of Judah,","T":"son of Amminadab, son of Ram, son of Hezron, son of Perez, son of Judah,"},
  "34": {"L":"the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor,","M":"the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor,","T":"son of Jacob, son of Isaac, son of Abraham, son of Terah, son of Nahor,"},
  "35": {"L":"the son of Serug, the son of Reu, the son of Peleg, the son of Eber, the son of Shelah,","M":"the son of Serug, the son of Reu, the son of Peleg, the son of Eber, the son of Shelah,","T":"son of Serug, son of Reu, son of Peleg, son of Eber, son of Shelah,"},
  "36": {"L":"the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech,","M":"the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech,","T":"son of Cainan, son of Arphaxad, son of Shem, son of Noah, son of Lamech,"},
  "37": {"L":"the son of Methuselah, the son of Enoch, the son of Jared, the son of Mahalaleel, the son of Cainan,","M":"the son of Methuselah, the son of Enoch, the son of Jared, the son of Mahalalel, the son of Kenan,","T":"son of Methuselah, son of Enoch, son of Jared, son of Mahalalel, son of Kenan,"},
  "38": {"L":"the son of Enos, the son of Seth, the son of Adam, the son of God.","M":"the son of Enosh, the son of Seth, the son of Adam, the son of God.","T":"son of Enosh, son of Seth, son of Adam—son of God."}
 },
 "4": {
  "1": {"L":"And Jesus, full of the Holy Spirit, returned from the Jordan and was led by the Spirit in the wilderness","M":"Jesus, full of the Holy Spirit, left the Jordan and was led by the Spirit into the wilderness,","T":"Jesus returned from the Jordan filled with the Holy Spirit and was led by the Spirit into the wilderness,"},
  "2": {"L":"for forty days, being tempted by the devil. And he ate nothing during those days. And when they were ended, he was hungry.","M":"where for forty days he was tempted by the devil. He ate nothing during those days, and at the end of them he was hungry.","T":"where for forty days he was tested by the devil. He ate nothing during that time, and at the end he was famished."},
  "3": {"L":"And the devil said to him: If you are the Son of God, command this stone to become bread.","M":"The devil said to him: If you are the Son of God, tell this stone to become bread.","T":"The devil said to him: If you really are the Son of God, order this stone to turn into bread."},
  "4": {"L":"And Jesus answered him: It is written, Man shall not live on bread alone.","M":"Jesus answered: It is written: Man shall not live on bread alone.","T":"Jesus replied: Scripture says, Human beings do not live on bread alone."},
  "5": {"L":"And the devil took him up and showed him all the kingdoms of the world in a moment of time,","M":"The devil led him up to a high place and showed him in an instant all the kingdoms of the world.","T":"The devil took him up and showed him all the kingdoms of the world in a single flash,"},
  "6": {"L":"and the devil said to him: To you I will give all this authority and their glory, for it has been delivered to me, and I give it to whom I will.","M":"And he said to him: I will give you all their authority and splendour; it has been given to me, and I can give it to anyone I want to.","T":"and said: I will give you all this power and glory—it has been handed to me and I can give it to anyone I choose."},
  "7": {"L":"If you therefore will worship before me, it shall all be yours.","M":"If you worship me, it will all be yours.","T":"All of it can be yours if you will bow down and worship me."},
  "8": {"L":"And Jesus answered him: It is written: You shall worship the Lord your God, and him only shall you serve.","M":"Jesus answered: It is written: Worship the Lord your God and serve him only.","T":"Jesus replied: Scripture says, Worship and serve the Lord your God alone."},
  "9": {"L":"And he took him to Jerusalem and set him on the pinnacle of the temple and said to him: If you are the Son of God, throw yourself down from here,","M":"The devil led him to Jerusalem and had him stand on the highest point of the temple. If you are the Son of God, he said, throw yourself down from here.","T":"The devil then led him to Jerusalem and placed him on the highest point of the temple and said: If you are the Son of God, throw yourself down from here—"},
  "10": {"L":"for it is written: He will command his angels concerning you, to guard you,","M":"For it is written: He will command his angels concerning you to guard you carefully;","T":"because Scripture says: He will instruct his angels to watch over you,"},
  "11": {"L":"and: On their hands they will bear you up, lest you strike your foot against a stone.","M":"they will lift you up in their hands, so that you will not strike your foot against a stone.","T":"and they will hold you up with their hands so you won't even stub your foot on a stone."},
  "12": {"L":"And Jesus answering said to him: It is said: You shall not put the Lord your God to the test.","M":"Jesus answered: It is said: Do not put the Lord your God to the test.","T":"Jesus replied: But Scripture also says, Do not put God to a reckless test."},
  "13": {"L":"And when the devil had finished every temptation, he departed from him until an opportune time.","M":"When the devil had finished all this tempting, he left him until an opportune time.","T":"When the devil had exhausted every test, he left Jesus—until a more suitable opportunity."},
  "14": {"L":"And Jesus returned in the power of the Spirit to Galilee, and a report about him went out through all the surrounding region.","M":"Jesus returned to Galilee in the power of the Spirit, and news about him spread through the whole countryside.","T":"Jesus returned to Galilee in the power of the Spirit, and word about him spread throughout the whole surrounding region."},
  "15": {"L":"And he was teaching in their synagogues, being glorified by all.","M":"He was teaching in their synagogues, and everyone praised him.","T":"He taught in the synagogues and was praised by everyone."},
  "16": {"L":"And he came to Nazareth, where he had been brought up. And as was his custom, he went to the synagogue on the Sabbath day, and he stood up to read.","M":"He went to Nazareth, where he had been brought up, and on the Sabbath day he went into the synagogue, as was his custom. He stood up to read,","T":"He came to Nazareth, where he had grown up. On the Sabbath he went to the synagogue as was his habit and stood up to read."},
  "17": {"L":"And the scroll of the prophet Isaiah was given to him. He unrolled the scroll and found the place where it was written:","M":"and the scroll of the prophet Isaiah was handed to him. Unrolling it, he found the place where it is written:","T":"The scroll of the prophet Isaiah was handed to him. He unrolled it and found the passage that reads:"},
  "18": {"L":"The Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor. He has sent me to proclaim release to the captives and recovery of sight to the blind, to set at liberty those who are oppressed,","M":"The Spirit of the Lord is on me, because he has anointed me to proclaim good news to the poor. He has sent me to proclaim freedom for the prisoners and recovery of sight for the blind, to set the oppressed free,","T":"The Spirit of the Lord is on me—he has anointed me to bring good news to the poor. He has sent me to announce freedom to captives, sight to the blind, to release those who are crushed,"},
  "19": {"L":"to proclaim the year of the Lord's favor.","M":"to proclaim the year of the Lord's favour.","T":"to declare the year when the Lord shows his favor."},
  "20": {"L":"And he rolled up the scroll and gave it back to the attendant and sat down. And the eyes of all in the synagogue were fixed on him.","M":"Then he rolled up the scroll, gave it back to the attendant and sat down. The eyes of everyone in the synagogue were fastened on him.","T":"He rolled up the scroll, returned it to the attendant, and sat down. Every eye in the synagogue was fixed on him."},
  "21": {"L":"And he began to say to them: Today this Scripture has been fulfilled in your hearing.","M":"He began by saying to them: Today this scripture is fulfilled in your hearing.","T":"He began: Today, as you have heard it, this scripture has come true."},
  "22": {"L":"And all were speaking well of him and were marveling at the gracious words that were coming from his mouth, and they were saying: Is this not Joseph's son?","M":"All spoke well of him and were amazed at the gracious words that came from his lips. Isn't this Joseph's son? they asked.","T":"Everyone was speaking well of him, astonished at the words of grace that poured from his mouth. They asked: Isn't this Joseph's son?"},
  "23": {"L":"And he said to them: Doubtless you will quote to me this proverb: Physician, heal yourself. What we have heard that you did at Capernaum, do here in your hometown as well.","M":"Jesus said to them: Surely you will quote this proverb to me: Physician, heal yourself! And you will tell me: Do here in your home town what we have heard that you did in Capernaum.","T":"He said: No doubt you'll throw this proverb at me: Doctor, heal yourself! Do here in your hometown what we've heard you did in Capernaum."},
  "24": {"L":"Truly, I say to you, no prophet is acceptable in his hometown.","M":"Truly I tell you, he continued, no prophet is accepted in his home town.","T":"I tell you honestly: no prophet is welcomed in his own hometown."},
  "25": {"L":"But in truth I tell you, there were many widows in Israel in the days of Elijah, when the heavens were shut up three years and six months, and a great famine came over all the land,","M":"I assure you that there were many widows in Israel in Elijah's time, when the sky was shut for three and a half years and there was a severe famine throughout the land.","T":"Let me remind you: in Elijah's time there were many widows in Israel when no rain fell for three and a half years and famine gripped the land."},
  "26": {"L":"and Elijah was sent to none of them but only to Zarephath, in the land of Sidon, to a woman who was a widow.","M":"Yet Elijah was not sent to any of them, but to a widow in Zarephath in the region of Sidon.","T":"Yet Elijah was sent to none of them—only to a widow in Zarephath, in Sidon."},
  "27": {"L":"And there were many lepers in Israel in the time of the prophet Elisha, and none of them was cleansed, but only Naaman the Syrian.","M":"And there were many in Israel with leprosy in the time of Elisha the prophet, yet not one of them was cleansed—only Naaman the Syrian.","T":"And in Elisha's time there were many with leprosy in Israel—yet not one of them was healed, only Naaman the Syrian."},
  "28": {"L":"When they heard these things, all in the synagogue were filled with wrath.","M":"All the people in the synagogue were furious when they heard this.","T":"When they heard this, everyone in the synagogue was filled with rage."},
  "29": {"L":"And they rose up and drove him out of the city and led him to the brow of the hill on which their city was built, so as to throw him down the cliff.","M":"They got up, drove him out of the town, and took him to the brow of the hill on which the town was built, in order to throw him off the cliff.","T":"They rose up, expelled him from the town, and drove him to the cliff edge of the hill on which Nazareth stood, intending to throw him off."},
  "30": {"L":"But passing through their midst, he went away.","M":"But he walked right through the crowd and went on his way.","T":"But he walked straight through the crowd and went on his way."},
  "31": {"L":"And he went down to Capernaum, a city of Galilee. And he was teaching them on the Sabbath,","M":"Then he went down to Capernaum, a town in Galilee, and on the Sabbath he taught the people.","T":"He went down to Capernaum, a town in Galilee, and taught there on the Sabbath."},
  "32": {"L":"and they were astonished at his teaching, for his word was with authority.","M":"They were amazed at his teaching, because his words had authority.","T":"They were astonished at his teaching—he spoke with genuine authority."},
  "33": {"L":"And in the synagogue there was a man who had the spirit of an unclean demon, and he cried out with a loud voice,","M":"In the synagogue there was a man possessed by a demon, an impure spirit. He cried out at the top of his voice:","T":"In the synagogue there was a man with an unclean demonic spirit who shrieked at the top of his voice:"},
  "34": {"L":"saying: Ha! What have we to do with you, Jesus of Nazareth? Have you come to destroy us? I know who you are—the Holy One of God!","M":"Go away! What do you want with us, Jesus of Nazareth? Have you come to destroy us? I know who you are—the Holy One of God!","T":"Leave us alone! What business do you have with us, Jesus of Nazareth? Have you come to destroy us? I know who you are—the Holy One of God!"},
  "35": {"L":"But Jesus rebuked him, saying: Be silent and come out of him! And when the demon had thrown him down in their midst, he came out of him, having done him no harm.","M":"Be quiet! Jesus said sternly. Come out of him! Then the demon threw the man down before them all and came out without injuring him.","T":"Jesus rebuked it sharply: Be quiet! Come out of him! The demon hurled the man down in the middle of the crowd and came out without hurting him."},
  "36": {"L":"And amazement came upon them all, and they spoke with one another, saying: What is this word? For with authority and power he commands the unclean spirits, and they come out!","M":"All the people were amazed and said to each other: What words these are! With authority and power he gives orders to impure spirits and they come out!","T":"Everyone was stunned and kept saying to each other: What is this? He commands unclean spirits with real authority and power—and they obey!"},
  "37": {"L":"And reports about him went out into every place in the surrounding region.","M":"And the news about him spread throughout the surrounding area.","T":"And word about him spread to every corner of the surrounding region."},
  "38": {"L":"And he arose and left the synagogue and entered Simon's house. Now Simon's mother-in-law was ill with a high fever, and they appealed to him on her behalf.","M":"Jesus left the synagogue and went to the home of Simon. Now Simon's mother-in-law was suffering from a high fever, and they asked Jesus to help her.","T":"Jesus left the synagogue and went to Simon's home. Simon's mother-in-law was suffering from a severe fever, and they appealed to Jesus for her."},
  "39": {"L":"And he stood over her and rebuked the fever, and it left her. And immediately she rose and began to serve them.","M":"So he bent over her and rebuked the fever, and it left her. She got up at once and began to wait on them.","T":"He stood over her, rebuked the fever, and it left her instantly. She got up at once and began serving them."},
  "40": {"L":"Now when the sun was setting, all those who had any who were sick with various diseases brought them to him, and he laid his hands on every one of them and healed them.","M":"At sunset, the people brought to Jesus all who had various kinds of illness, and laying his hands on each one, he healed them.","T":"As the sun was setting, people brought to Jesus everyone who was sick with any kind of disease. He laid his hands on each one and healed them."},
  "41": {"L":"And demons also came out of many, crying out: You are the Son of God! But he rebuked them and would not allow them to speak, because they knew that he was the Christ.","M":"Moreover, demons came out of many people, shouting: You are the Son of God! But he rebuked them and would not allow them to speak, because they knew he was the Messiah.","T":"Demons came out of many people, shouting: You are the Son of God! But he rebuked them and refused to let them speak, because they knew he was the Messiah."},
  "42": {"L":"And when it was day, he departed and went into a desolate place. And the crowds sought him, and came to him and tried to keep him from leaving them.","M":"At daybreak, Jesus went out to a solitary place. The people were looking for him and when they came to where he was, they tried to keep him from leaving them.","T":"At daybreak Jesus went out to a deserted place. The crowds searched for him, and when they found him they tried to prevent him from leaving."},
  "43": {"L":"But he said to them: I must proclaim the good news of the kingdom of God to the other cities also, for I was sent for this purpose.","M":"But he said: I must proclaim the good news of the kingdom of God to the other towns also, because that is why I was sent.","T":"But he said: I must announce the good news of God's kingdom to the other towns as well—this is why I was sent."},
  "44": {"L":"And he was preaching in the synagogues of Judea.","M":"And he kept on preaching in the synagogues of Judea.","T":"And he went on preaching in the synagogues of Judea."}
 },
 "5": {
  "1": {"L":"Now it came to pass, while the crowd was pressing about him to hear the word of God, that he was standing by the lake of Gennesaret,","M":"One day as Jesus was standing by the Lake of Gennesaret, the people were crowding around him and listening to the word of God.","T":"One day the crowd was pressing in around Jesus to hear God's word as he stood beside the Lake of Gennesaret."},
  "2": {"L":"and he saw two boats by the lake, but the fishermen had gone out of them and were washing their nets.","M":"He saw at the water's edge two boats, left there by the fishermen, who were washing their nets.","T":"He noticed two boats pulled up at the water's edge—the fishermen had left them and were washing their nets."},
  "3": {"L":"And getting into one of the boats, which was Simon's, he asked him to put out a little from the land. And he sat down and taught the crowds from the boat.","M":"He got into one of the boats, the one belonging to Simon, and asked him to put out a little from the shore. Then he sat down and taught the people from the boat.","T":"He got into Simon's boat and asked him to push out a little from shore. Then he sat down in the boat and taught the crowds."},
  "4": {"L":"And when he had finished speaking, he said to Simon: Put out into the deep water, and let down your nets for a catch.","M":"When he had finished speaking, he said to Simon: Put out into deep water, and let down the nets for a catch.","T":"When he had finished teaching, he said to Simon: Push out into deep water and let down your nets for a catch."},
  "5": {"L":"And Simon answered: Master, we worked hard all night and caught nothing. But at your word I will let down the nets.","M":"Simon answered: Master, we've worked hard all night and haven't caught anything. But because you say so, I will let down the nets.","T":"Simon replied: Master, we worked all night without catching a thing. But because you say so, I'll let down the nets."},
  "6": {"L":"And when they had done this, they enclosed a great shoal of fish, and their nets were breaking.","M":"When they had done so, they caught such a large number of fish that their nets began to break.","T":"When they did, they netted such an enormous haul of fish that their nets began to tear."},
  "7": {"L":"And they signaled to their partners in the other boat to come and help them. And they came and filled both the boats, so that they began to sink.","M":"So they signalled their partners in the other boat to come and help them, and they came and filled both boats so full that they began to sink.","T":"They waved to their partners in the other boat to come and help. They came, and both boats were so loaded they began to sink."},
  "8": {"L":"But when Simon Peter saw it, he fell down at Jesus' knees, saying: Depart from me, for I am a sinful man, O Lord.","M":"When Simon Peter saw this, he fell at Jesus' knees and said: Go away from me, Lord; I am a sinful man!","T":"When Simon Peter saw this, he dropped to his knees before Jesus and said: Go away from me, Lord—I am a sinful man!"},
  "9": {"L":"For he and all who were with him were amazed at the catch of fish that they had taken,","M":"For he and all his companions were astonished at the catch of fish they had taken,","T":"He and all his companions were awestruck at the catch they had taken,"},
  "10": {"L":"and so also were James and John, sons of Zebedee, who were partners with Simon. And Jesus said to Simon: Do not fear; from now on you will be catching men.","M":"and so were James and John, the sons of Zebedee, Simon's partners. Then Jesus said to Simon: Don't be afraid; from now on you will fish for people.","T":"including James and John, the sons of Zebedee, Simon's partners. Jesus said to Simon: Don't be afraid. From now on you'll be catching people."},
  "11": {"L":"And when they had brought their boats to land, they left everything and followed him.","M":"So they pulled their boats up on shore, left everything and followed him.","T":"They brought their boats to shore, abandoned everything, and followed him."},
  "12": {"L":"And it came to pass that while he was in one of the cities, behold, there was a man full of leprosy; and when he saw Jesus, he fell on his face and begged him, saying: Lord, if you are willing, you can make me clean.","M":"While Jesus was in one of the towns, a man came along who was covered with leprosy. When he saw Jesus, he fell with his face to the ground and begged him: Lord, if you are willing, you can make me clean.","T":"While Jesus was in one of the towns, a man covered with leprosy saw him and fell with his face to the ground, begging: Lord, if you are willing, you can make me clean."},
  "13": {"L":"And Jesus stretched out his hand and touched him, saying: I am willing; be clean. And immediately the leprosy departed from him.","M":"Jesus reached out his hand and touched the man. I am willing, he said. Be clean! And immediately the leprosy left him.","T":"Jesus reached out and touched him. I am willing, he said. Be clean! Immediately the leprosy vanished."},
  "14": {"L":"And he charged him to tell no one. But go and show yourself to the priest, and make an offering for your cleansing, as Moses commanded, as a testimony to them.","M":"Then Jesus ordered him: Don't tell anyone, but go, show yourself to the priest and offer the sacrifices that Moses commanded for your cleansing, as a testimony to them.","T":"Jesus instructed him: Tell no one. But go and present yourself to the priest and offer what Moses prescribed for your cleansing—as a witness to them."},
  "15": {"L":"But the report about him spread all the more, and great crowds gathered to hear him and to be healed of their infirmities.","M":"Yet the news about him spread all the more, so that crowds of people came to hear him and to be healed of their illnesses.","T":"Yet word about him spread even further, and large crowds gathered to hear him and to be healed of their sicknesses."},
  "16": {"L":"But he would withdraw to desolate places and pray.","M":"But Jesus often withdrew to lonely places and prayed.","T":"But Jesus would regularly withdraw to deserted places to pray."},
  "17": {"L":"And it came to pass on one of those days, that he was teaching. And there were Pharisees and teachers of the law sitting there who had come from every village of Galilee and Judea and from Jerusalem. And the power of the Lord was with him to heal.","M":"One day Jesus was teaching, and Pharisees and teachers of the law were sitting there. They had come from every village of Galilee and from Judea and Jerusalem. And the power of the Lord was with Jesus to heal the sick.","T":"One day as Jesus was teaching, Pharisees and teachers of the law were seated there—they had come from every town in Galilee and Judea and from Jerusalem. The power of the Lord was present to heal."},
  "18": {"L":"And behold, some men were bringing on a bed a man who was paralyzed, and they were seeking to bring him in and lay him before Jesus.","M":"Some men came carrying a paralysed man on a mat and tried to take him into the house to lay him before Jesus.","T":"Some men arrived carrying a paralyzed man on a mat, trying to bring him in and lay him before Jesus."},
  "19": {"L":"And finding no way to bring him in because of the crowd, they went up on the roof and let him down with his bed through the tiles into the midst before Jesus.","M":"When they could not find a way to do this because of the crowd, they went up on the roof and lowered him on his mat through the tiles into the middle of the crowd, right in front of Jesus.","T":"Unable to get through because of the crowd, they went up on the roof and lowered the man on his mat down through the tiles, right in front of Jesus."},
  "20": {"L":"And when he saw their faith, he said: Man, your sins are forgiven you.","M":"When Jesus saw their faith, he said: Friend, your sins are forgiven.","T":"When Jesus saw their faith, he said: Friend, your sins are forgiven."},
  "21": {"L":"And the scribes and the Pharisees began to question, saying: Who is this who speaks blasphemies? Who can forgive sins but God alone?","M":"The Pharisees and the teachers of the law began thinking to themselves: Who is this fellow who speaks blasphemy? Who can forgive sins but God alone?","T":"The Pharisees and teachers of the law started saying to each other: Who does this man think he is? This is blasphemy! Who can forgive sins except God alone?"},
  "22": {"L":"But when Jesus perceived their questionings, he answered them: Why are you questioning in your hearts?","M":"Jesus knew what they were thinking and asked: Why are you thinking these things in your hearts?","T":"Jesus knew what they were thinking and said: Why do you have such thoughts?"},
  "23": {"L":"Which is easier, to say: Your sins are forgiven you, or to say: Rise and walk?","M":"Which is easier: to say, Your sins are forgiven, or to say, Get up and walk?","T":"Which is easier to say: Your sins are forgiven—or: Get up and walk?"},
  "24": {"L":"But that you may know that the Son of Man has authority on earth to forgive sins—he said to the man who was paralyzed: I say to you, rise, take up your bed and go to your home.","M":"But I want you to know that the Son of Man has authority on earth to forgive sins. So he said to the paralysed man: I tell you, get up, take your mat and go home.","T":"But so you may know that the Son of Man has authority on earth to forgive sins— he turned to the paralyzed man and said: I tell you, get up, pick up your mat, and go home."},
  "25": {"L":"And immediately he rose up before them and took up what he had been lying on and went to his home, glorifying God.","M":"Immediately he stood up in front of them, took what he had been lying on and went home praising God.","T":"Instantly the man stood up before them all, picked up what he had been lying on, and went home praising God."},
  "26": {"L":"And astonishment seized them all, and they glorified God, and were filled with fear, saying: We have seen extraordinary things today.","M":"Everyone was amazed and gave praise to God. They were filled with awe and said: We have seen remarkable things today.","T":"Amazement gripped everyone. They praised God and were filled with awe, saying: We have seen extraordinary things today."},
  "27": {"L":"And after these things he went out and saw a tax collector named Levi, sitting at the tax booth. And he said to him: Follow me.","M":"After this, Jesus went out and saw a tax collector by the name of Levi sitting at his tax booth. Follow me, Jesus said to him,","T":"After this Jesus went out and saw a tax collector named Levi sitting at his collection booth. Jesus said: Follow me."},
  "28": {"L":"And leaving everything, he rose and followed him.","M":"and Levi got up, left everything and followed him.","T":"Levi got up, left everything behind, and followed him."},
  "29": {"L":"And Levi gave a great feast for him in his house, and there was a large company of tax collectors and others reclining at table with them.","M":"Then Levi held a great banquet for Jesus at his house, and a large crowd of tax collectors and others were eating with them.","T":"Then Levi threw a great banquet for Jesus at his home. A large crowd of tax collectors and others were reclining at the table with them."},
  "30": {"L":"And the Pharisees and their scribes grumbled at his disciples, saying: Why do you eat and drink with tax collectors and sinners?","M":"But the Pharisees and the teachers of the law who belonged to their sect complained to his disciples: Why do you eat and drink with tax collectors and sinners?","T":"The Pharisees and their religious scholars complained to his disciples: Why do you eat and drink with tax collectors and sinners?"},
  "31": {"L":"And Jesus answered them: Those who are well have no need of a physician, but those who are sick.","M":"Jesus answered them: It is not the healthy who need a doctor, but the sick.","T":"Jesus replied: Healthy people don't need a doctor—sick people do."},
  "32": {"L":"I have not come to call the righteous but sinners to repentance.","M":"I have not come to call the righteous, but sinners to repentance.","T":"I came not to call the self-righteous, but to call sinners to turn back to God."},
  "33": {"L":"And they said to him: The disciples of John fast often and offer prayers, and so do the disciples of the Pharisees, but yours eat and drink.","M":"They said to him: John's disciples often fast and pray, and so do the disciples of the Pharisees, but yours go on eating and drinking.","T":"They said to him: John's disciples fast frequently and pray, and the Pharisees' disciples do the same—but your disciples just eat and drink."},
  "34": {"L":"And Jesus said to them: Can you make the sons of the bridal chamber fast while the bridegroom is with them?","M":"Jesus answered: Can you make the friends of the bridegroom fast while he is with them?","T":"Jesus replied: You can't ask the wedding party to fast while the bridegroom is right there with them, can you?"},
  "35": {"L":"But the days will come when the bridegroom is taken from them, and then they will fast in those days.","M":"But the time will come when the bridegroom will be taken from them; in those days they will fast.","T":"But the days are coming when the bridegroom will be taken away—and then they will fast."},
  "36": {"L":"He also told them a parable: No one tears a patch from a new garment and sews it on an old garment. If he does, he will both tear the new one, and the patch from the new will not match the old.","M":"He told them this parable: No one tears a piece out of a new garment to patch an old one. Otherwise, they will have torn the new garment, and the patch from the new will not match the old.","T":"He also gave them this parable: No one cuts a patch from a new garment to repair an old one—that would ruin the new garment, and the new patch wouldn't match the old anyway."},
  "37": {"L":"And no one puts new wine into old wineskins. If he does, the new wine will burst the skins and it will be spilled, and the skins will be destroyed.","M":"And no one pours new wine into old wineskins. Otherwise, the new wine will burst the skins; the wine will run out and the wineskins will be ruined.","T":"And no one pours new wine into old wineskins—the new wine will split the old skins, spilling the wine and ruining the skins."},
  "38": {"L":"But new wine must be put into new wineskins.","M":"No, new wine must be poured into new wineskins.","T":"New wine belongs in new wineskins."},
  "39": {"L":"And no one after drinking old wine desires new, for he says: The old is good.","M":"And no one after drinking old wine wants the new, for they say, The old is better.","T":"And no one who has been drinking old wine wants the new—they say, The old is better."}
 },
 "6": {
  "1": {"L":"Now it came to pass on a Sabbath, while he was going through the grain fields, his disciples plucked and ate the heads of grain, rubbing them in their hands.","M":"One Sabbath Jesus was going through the grain fields, and his disciples began to pick some heads of grain, rub them in their hands and eat the kernels.","T":"One Sabbath Jesus was walking through the grain fields, and his disciples were picking heads of grain, rubbing them in their hands, and eating them."},
  "2": {"L":"But some of the Pharisees said: Why are you doing what is not lawful on the Sabbath?","M":"Some of the Pharisees asked: Why are you doing what is unlawful on the Sabbath?","T":"Some Pharisees said: Why are you doing what is not permitted on the Sabbath?"},
  "3": {"L":"And Jesus answered them: Have you not read what David did when he was hungry, he and those who were with him—","M":"Jesus answered them: Have you never read what David did when he and his companions were hungry?","T":"Jesus replied: Haven't you read what David did when he and his men were hungry?"},
  "4": {"L":"how he entered the house of God and took and ate the bread of the Presence, which is not lawful for any but the priests to eat, and also gave some to those with him?","M":"He entered the house of God, and taking the consecrated bread, he ate what is lawful only for priests to eat. And he also gave some to his companions.","T":"He went into God's house and took the consecrated bread—which only priests are allowed to eat—and ate it, and gave some to his companions."},
  "5": {"L":"And he said to them: The Son of Man is lord of the Sabbath.","M":"Then Jesus said to them: The Son of Man is Lord of the Sabbath.","T":"Then he told them: The Son of Man is master even of the Sabbath."},
  "6": {"L":"On another Sabbath he entered the synagogue and was teaching, and a man was there whose right hand was withered.","M":"On another Sabbath he went into the synagogue and was teaching, and a man was there whose right hand was shrivelled.","T":"On another Sabbath he entered the synagogue and was teaching. A man was there whose right hand was withered."},
  "7": {"L":"And the scribes and the Pharisees watched him, to see whether he would heal on the Sabbath, so that they might find a reason to accuse him.","M":"The Pharisees and the teachers of the law were looking for a reason to accuse Jesus, so they watched him closely to see if he would heal on the Sabbath.","T":"The religious scholars and Pharisees were watching closely to see if he would heal on the Sabbath, looking for grounds to accuse him."},
  "8": {"L":"But he knew their thoughts, and he said to the man with the withered hand: Rise and stand here. And he rose and stood there.","M":"But Jesus knew what they were thinking and said to the man with the shrivelled hand: Get up and stand in front of everyone. So he got up and stood there.","T":"But Jesus knew their thoughts and said to the man with the withered hand: Get up and stand out here. The man got up and stood there."},
  "9": {"L":"And Jesus said to them: I ask you, is it lawful on the Sabbath to do good or to do harm, to save life or to destroy it?","M":"Then Jesus said to them: I ask you, which is lawful on the Sabbath: to do good or to do evil, to save life or to destroy it?","T":"Jesus said to them: Let me ask you something: on the Sabbath, which is the right thing to do—good or evil? To save life or to destroy it?"},
  "10": {"L":"And looking around at them all, he said to him: Stretch out your hand. And he did so, and his hand was restored.","M":"He looked around at them all, and then said to the man: Stretch out your hand. He did so, and his hand was completely restored.","T":"He looked around at all of them and said to the man: Stretch out your hand. He did—and his hand was completely restored."},
  "11": {"L":"But they were filled with fury and discussed with one another what they might do to Jesus.","M":"But the Pharisees and the teachers of the law were furious and began to discuss with one another what they might do to Jesus.","T":"They were filled with rage and began discussing what they might do to Jesus."},
  "12": {"L":"And it came to pass in those days that he went out to the mountain to pray, and he continued all night in prayer to God.","M":"One of those days Jesus went out to a mountainside to pray, and spent the night praying to God.","T":"In those days Jesus went out to the hill country to pray and spent the whole night in prayer to God."},
  "13": {"L":"And when it was day, he called his disciples and chose from them twelve, whom he also named apostles:","M":"When morning came, he called his disciples to him and chose twelve of them, whom he also designated apostles:","T":"When morning came, he called his disciples together and chose twelve of them, whom he also designated as apostles:"},
  "14": {"L":"Simon, whom he also named Peter, and Andrew his brother, and James and John, and Philip and Bartholomew,","M":"Simon (whom he named Peter), his brother Andrew, James, John, Philip, Bartholomew,","T":"Simon, whom he named Peter, and his brother Andrew; James and John; Philip and Bartholomew;"},
  "15": {"L":"and Matthew and Thomas, and James the son of Alphaeus, and Simon who was called the Zealot,","M":"Matthew, Thomas, James son of Alphaeus, Simon who was called the Zealot,","T":"Matthew and Thomas; James son of Alphaeus; Simon who was called the Zealot;"},
  "16": {"L":"and Judas the son of James, and Judas Iscariot, who became a traitor.","M":"Judas son of James, and Judas Iscariot, who became a traitor.","T":"Judas son of James; and Judas Iscariot, who later betrayed him."},
  "17": {"L":"And he came down with them and stood on a level place, with a great crowd of his disciples and a great multitude of people from all Judea and Jerusalem and the seacoast of Tyre and Sidon,","M":"He went down with them and stood on a level place. A large crowd of his disciples was there and a great number of people from all over Judea, from Jerusalem, and from the coastal region around Tyre and Sidon,","T":"He came down with them and stood on a level place. A large crowd of his disciples was there, along with an enormous gathering from all over Judea, from Jerusalem, and from the coast of Tyre and Sidon."},
  "18": {"L":"who came to hear him and to be healed of their diseases. And those who were troubled by unclean spirits were cured.","M":"who had come to hear him and to be healed of their diseases. Those troubled by impure spirits were cured,","T":"They had come to hear him and to be healed of their diseases. Those tormented by unclean spirits were being freed,"},
  "19": {"L":"And all the crowd sought to touch him, for power was going out from him and healing them all.","M":"and the people all tried to touch him, because power was coming from him and healing them all.","T":"and everyone in the crowd was trying to touch him—because power was flowing from him and healing them all."},
  "20": {"L":"And he lifted up his eyes on his disciples, and said: Blessed are you who are poor, for yours is the kingdom of God.","M":"Looking at his disciples, he said: Blessed are you who are poor, for yours is the kingdom of God.","T":"Looking at his disciples, he said: You who are poor are favored by God—the kingdom of God belongs to you."},
  "21": {"L":"Blessed are you who are hungry now, for you shall be satisfied. Blessed are you who weep now, for you shall laugh.","M":"Blessed are you who hunger now, for you will be satisfied. Blessed are you who weep now, for you will laugh.","T":"You who are hungry now are favored by God—you will be satisfied. You who weep now are favored—you will laugh."},
  "22": {"L":"Blessed are you when people hate you and when they exclude you and revile you and spurn your name as evil, on account of the Son of Man!","M":"Blessed are you when people hate you, when they exclude you and insult you and reject your name as evil, because of the Son of Man.","T":"You are favored by God when people hate you, shut you out, insult you, and reject your name as evil—because of the Son of Man."},
  "23": {"L":"Rejoice in that day, and leap for joy, for behold, your reward is great in heaven; for so their fathers did to the prophets.","M":"Rejoice in that day and leap for joy, because great is your reward in heaven. For that is how their ancestors treated the prophets.","T":"Rejoice and leap for joy when that happens—your reward in heaven is enormous. For that is exactly how their ancestors treated the prophets."},
  "24": {"L":"But woe to you who are rich, for you have received your consolation.","M":"But woe to you who are rich, for you have already received your comfort.","T":"But watch out, you who are wealthy—you have already received your comfort in full."},
  "25": {"L":"Woe to you who are full now, for you shall be hungry. Woe to you who laugh now, for you shall mourn and weep.","M":"Woe to you who are well fed now, for you will go hungry. Woe to you who laugh now, for you will mourn and weep.","T":"Watch out, you who are stuffed full now—you will go hungry. Watch out, you who are laughing now—you will mourn and weep."},
  "26": {"L":"Woe to you, when all people speak well of you, for so their fathers did to the false prophets.","M":"Woe to you when everyone speaks well of you, for that is how their ancestors treated the false prophets.","T":"Watch out when everyone speaks well of you—that is exactly how their ancestors treated the false prophets."},
  "27": {"L":"But I say to you who hear: Love your enemies, do good to those who hate you,","M":"But to you who are listening I say: Love your enemies, do good to those who hate you,","T":"But to you who are listening I say: Love your enemies. Do good to those who hate you."},
  "28": {"L":"bless those who curse you, pray for those who abuse you.","M":"bless those who curse you, pray for those who ill-treat you.","T":"Speak well of those who curse you. Pray for those who treat you badly."},
  "29": {"L":"To one who strikes you on the cheek, offer the other also, and from one who takes away your cloak do not withhold your tunic either.","M":"If someone slaps you on one cheek, turn to them the other also. If someone takes your coat, do not withhold your shirt from them.","T":"If someone strikes you on the cheek, offer the other one as well. If someone takes your outer coat, don't stop them from taking your shirt too."},
  "30": {"L":"Give to everyone who begs from you, and from one who takes away your goods do not demand them back.","M":"Give to everyone who asks you, and if anyone takes what belongs to you, do not demand it back.","T":"Give to everyone who asks, and if someone takes what is yours, don't demand it back."},
  "31": {"L":"And as you wish that others would do to you, do so to them.","M":"Do to others as you would have them do to you.","T":"Treat others the way you want them to treat you."},
  "32": {"L":"If you love those who love you, what benefit is that to you? For even sinners love those who love them.","M":"If you love those who love you, what credit is that to you? Even sinners love those who love them.","T":"If you only love those who love you back, what credit does that earn you? Even sinners love those who love them."},
  "33": {"L":"And if you do good to those who do good to you, what benefit is that to you? For even sinners do the same.","M":"And if you do good to those who are good to you, what credit is that to you? Even sinners do that.","T":"If you only do good to people who are good to you, what credit is that? Even sinners do the same."},
  "34": {"L":"And if you lend to those from whom you expect to receive, what benefit is that to you? Even sinners lend to sinners, to get back the same amount.","M":"And if you lend to those from whom you expect repayment, what credit is that to you? Even sinners lend to sinners, expecting to be repaid in full.","T":"And if you only lend to people you expect will repay you, what credit is that? Even sinners lend to sinners expecting to be paid back."},
  "35": {"L":"But love your enemies, and do good, and lend, expecting nothing in return, and your reward will be great, and you will be sons of the Most High, for he is kind to the ungrateful and the evil.","M":"But love your enemies, do good to them, and lend to them without expecting to get anything back. Then your reward will be great, and you will be children of the Most High, because he is kind to the ungrateful and wicked.","T":"Instead, love your enemies, do good, and lend without expecting anything in return. Then your reward will be great, and you will be children of the Most High—because he is kind even to the ungrateful and the wicked."},
  "36": {"L":"Be merciful, even as your Father is merciful.","M":"Be merciful, just as your Father is merciful.","T":"Be compassionate, as your Father is compassionate."},
  "37": {"L":"Judge not, and you will not be judged; condemn not, and you will not be condemned; forgive, and you will be forgiven;","M":"Do not judge, and you will not be judged. Do not condemn, and you will not be condemned. Forgive, and you will be forgiven.","T":"Stop judging, and you will not be judged. Stop condemning, and you will not be condemned. Forgive, and you will be forgiven."},
  "38": {"L":"give, and it will be given to you. Good measure, pressed down, shaken together, running over, will be put into your lap. For with the measure you use it will be measured back to you.","M":"Give, and it will be given to you. A good measure, pressed down, shaken together and running over, will be poured into your lap. For with the measure you use, it will be measured to you.","T":"Give, and you will receive—a full measure, pressed down, shaken together, and overflowing will be poured into your lap. Because the same standard you apply to others will be applied back to you."},
  "39": {"L":"He also told them a parable: Can a blind man lead a blind man? Will they not both fall into a pit?","M":"He also told them this parable: Can the blind lead the blind? Will they not both fall into a pit?","T":"He told them this parable: Can a blind person lead another blind person? Won't they both fall into a ditch?"},
  "40": {"L":"A disciple is not above his teacher, but everyone when he is fully trained will be like his teacher.","M":"The student is not above the teacher, but everyone who is fully trained will be like their teacher.","T":"A student is not above their teacher, but when fully trained, a student will be like their teacher."},
  "41": {"L":"Why do you see the speck that is in your brother's eye, but do not notice the log that is in your own eye?","M":"Why do you look at the speck of sawdust in your brother's eye and pay no attention to the plank in your own eye?","T":"Why are you focused on the speck in your friend's eye when you have a plank in your own?"},
  "42": {"L":"How can you say to your brother: Brother, let me take out the speck that is in your eye, when you yourself do not see the log that is in your own eye? You hypocrite, first take the log out of your own eye, and then you will see clearly to take out the speck that is in your brother's eye.","M":"How can you say to your brother: Brother, let me take the speck out of your eye, when you yourself fail to see the plank in your own eye? You hypocrite, first take the plank out of your eye, and then you will see clearly to remove the speck from your brother's eye.","T":"How can you say to your friend: Let me remove that speck from your eye—when you can't see the plank in your own? Hypocrite! First remove the plank from your own eye, and then you'll see clearly enough to remove the speck from your friend's."},
  "43": {"L":"For no good tree bears bad fruit, nor again does a bad tree bear good fruit,","M":"No good tree bears bad fruit, nor does a bad tree bear good fruit.","T":"A healthy tree doesn't bear bad fruit, and a diseased tree doesn't bear good fruit."},
  "44": {"L":"for each tree is known by its own fruit. For figs are not gathered from thornbushes, nor are grapes picked from a bramble bush.","M":"Each tree is recognised by its own fruit. People do not pick figs from thorn-bushes, or grapes from briers.","T":"Each tree is known by its own fruit. You don't harvest figs from thornbushes or grapes from briars."},
  "45": {"L":"The good person out of the good treasure of his heart produces good, and the evil person out of his evil treasure produces evil, for out of the abundance of the heart his mouth speaks.","M":"A good man brings good things out of the good stored up in his heart, and an evil man brings evil things out of the evil stored up in his heart. For the mouth speaks what the heart is full of.","T":"A good person draws good things from the good stored up in their heart, and an evil person draws evil from the evil stored up in theirs. For what the mouth says flows from what fills the heart."},
  "46": {"L":"Why do you call me Lord, Lord, and not do what I tell you?","M":"Why do you call me, Lord, Lord, and do not do what I say?","T":"Why do you keep calling me Lord, Lord—but don't do what I say?"},
  "47": {"L":"Everyone who comes to me and hears my words and does them, I will show you what he is like:","M":"As for everyone who comes to me and hears my words and puts them into practice, I will show you what they are like.","T":"Let me show you what the person who comes to me, hears my words, and puts them into practice is like:"},
  "48": {"L":"he is like a man building a house, who dug deep and laid the foundation on the rock. And when a flood arose, the stream broke against that house and could not shake it, because it had been well built.","M":"They are like a man building a house, who dug down deep and laid the foundation on rock. When a flood came, the torrent struck that house but could not shake it, because it was well built.","T":"He is like a man who built a house by digging deep and laying the foundation on solid rock. When the floods came and the torrent beat against that house, it could not be shaken—it was solidly built."},
  "49": {"L":"But the one who hears and does not do them is like a man who built a house on the ground without a foundation. When the stream broke against it, immediately it fell, and the ruin of that house was great.","M":"But the one who hears my words and does not put them into practice is like a man who built a house on the ground without a foundation. The moment the torrent struck that house, it collapsed and its destruction was complete.","T":"But the person who hears my words and doesn't act on them is like a man who built a house on bare ground without a foundation. When the flood came and the torrent struck, it collapsed instantly—and the destruction was total."}
 }
}

def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'luke')
        for ch, verses in LUKE.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'luke', data)
    print('Luke chapters 1-6 written.')

if __name__ == '__main__':
    main()
